  getLeaveBalances(req: FastifyRequest, reply: FastifyReply): Promise<void>;
}

export class LeaveController implements ILeaveController {
  constructor(private readonly leaveService: ILeaveService) {}

  async createLeaveRequest(req: FastifyRequest<{ Body: CreateLeaveRequestBody }>, reply: FastifyReply): Promise<void> {
    try {
      const employeeId = (req as any).user.id;
      const result = await this.leaveService.createLeaveRequest(employeeId, req.body);
      reply.status(201).send(result);
    } catch (err) {
      reply.status(500).send({ statusCode: 500, error: 'Internal Server Error', message: 'An unexpected error occurred' });
    }
  }

  async getLeaveRequest(req: FastifyRequest<{ Params: GetLeaveRequestParams }>, reply: FastifyReply): Promise<void> {
    try {
      const employeeId = (req as any).user.id;
      const result = await this.leaveService.getLeaveRequest(req.params.id, employeeId);
