      const results = await this.leaveService.getMyLeaveRequests(employeeId);
      reply.status(200).send(results);
    } catch (err) {
      reply.status(500).send({ statusCode: 500, error: 'Internal Server Error', message: 'An unexpected error occurred' });
    }
  }

  async approveLeaveRequest(req: FastifyRequest<{ Params: ApproveLeaveRequestParams }>, reply: FastifyReply): Promise<void> {
