      const result = await this.leaveService.approveLeaveRequest(req.params.id, managerId);
      reply.status(200).send(result);
    } catch (err) {
      reply.status(500).send({ statusCode: 500, error: 'Internal Server Error', message: 'An unexpected error occurred' });
    }
  }

  async rejectLeaveRequest(req: FastifyRequest<{ Params: RejectLeaveRequestParams; Body: RejectLeaveRequestBody }>, reply: FastifyReply): Promise<void> {
    try {
      const managerId = (req as any).user.id;
      const result = await this.leaveService.rejectLeaveRequest(req.params.id, managerId, req.body.reason);
      reply.status(200).send(result);
    } catch (err) {
      reply.status(500).send({ statusCode: 500, error: 'Internal Server Error', message: 'An unexpected error occurred' });
    }
  }

  async cancelLeaveRequest(req: FastifyRequest<{ Params: CancelLeaveRequestParams }>, reply: FastifyReply): Promise<void> {
    try {
      const employeeId = (req as any).user.id;
      const result = await this.leaveService.cancelLeaveRequest(req.params.id, employeeId);
      reply.status(200).send(result);
    } catch (err) {
      reply.status(500).send({ statusCode: 500, error: 'Internal Server Error', message: 'An unexpected error occurred' });
    }
  }

  async getLeaveBalance(req: FastifyRequest<{ Params: { leaveTypeId: string } }>, reply: FastifyReply): Promise<void> {
    try {
      const employeeId = (req as any).user.id;
