        reply.status(404).send({ statusCode: 404, error: 'Not Found', message: 'Balance not found' });
        return;
      }
      reply.status(200).send(result);
    } catch (err) {
      reply.status(500).send({ statusCode: 500, error: 'Internal Server Error', message: 'An unexpected error occurred' });
    }
  }

  async getLeaveBalances(req: FastifyRequest, reply: FastifyReply): Promise<void> {
